#!/bin/sh
# GENERATED by cc-guides from .claude/fragments/plugin/scripts/install-binary.sh/ — do not edit; edit the fragments and push — CI renders.
# Provision the cc-sudo binary for the cc-sudo plugin.
#
# bin/cc-sudo is only ever a symlink — to a brew-installed binary, the
# durable download under the plugin data dir, or a local dev build. The payload
# never lives in the plugin dir itself: CLAUDE_PLUGIN_ROOT is ephemeral (the
# path swaps on every plugin update), while the data dir survives updates.
#
# Resolution order (semantic — reordering resurrects the dev-clobber bug):
#   1. symlink already resolves to the target release -> done
#   2. symlink resolves to a dev build                -> leave it alone
#   3. binary on PATH (brew-owned or otherwise)       -> symlink it, brew upgrade when stale
#   4. brew present, binary absent                    -> brew install, symlink
#   5. durable data-dir payload at target             -> re-symlink, no re-download
#   6. static download into the data dir              -> sha256-verify, symlink
#
# Consumer extension point: a sibling scripts/install-binary.extras.sh, when
# present, is sourced after TAG/BARE and before any arm runs — plugin-specific
# migrations go there, and redefining extras_on_exit() adds work to the EXIT
# trap. Ships from the consumer's own fragments; most plugins have none.
set -eu

NAME="cc-sudo"
REPO="yasyf/cc-sudo"
BREW_PKG="yasyf/tap/cc-sudo"
ROOT="$(cd "$(dirname "$0")/.." && pwd)"
LINK="$ROOT/bin/$NAME"
# CLAUDE_PLUGIN_DATA is only exported to hook/MCP subprocesses; bare shell runs
# fall back to its documented default.
DATA_DIR="${CLAUDE_PLUGIN_DATA:-$HOME/.claude/plugins/data/cc-sudo}"
BREW_LOCK="$DATA_DIR/brew.lock"
BREW_LOCK_MAX_AGE=600
BREW_LOCK_TOKEN="$$.$(date +%s)"
BREW_LOCK_HELD=0

# Rename-atomic: bare ln -sf unlinks then re-creates, and a concurrent caller
# exec'ing $LINK in that window sees ENOENT — fatal on the MCP path now that
# detached refreshes relink while callers run.
relink() {
  ln -sf "$1" "$LINK.$$"
  mv -f "$LINK.$$" "$LINK"
}

release_brew_lock() {
  [ "$BREW_LOCK_HELD" -eq 1 ] || return 0
  BREW_LOCK_HELD=0
  # Best-effort: a mismatched token means we were stale-broken and re-acquired
  # — leave it. The read-then-rm window can still delete a lock acquired in
  # between; that degrades to the pre-lock behavior.
  [ "$(cat "$BREW_LOCK/owner" 2>/dev/null)" = "$BREW_LOCK_TOKEN" ] || return 0
  rm -rf "$BREW_LOCK" 2>/dev/null || true
}

brew_lock_mtime() {
  case "$(uname -s)" in
    Darwin) stat -f %m "$BREW_LOCK" ;;
    *) stat -c %Y "$BREW_LOCK" ;;
  esac
}

# Fresh sessions fully serialize on the mkdir; after a crashed holder,
# stale-break/release are best-effort — rare races briefly admit
# concurrent brews, bounded by Homebrew's own locks.
break_stale_brew_lock() {
  # Asides are garbage from birth (they exist only between a breaker's mv
  # and rm, and mv inherits the old lock's mtime); reap on sight — a
  # concurrent double-reap is guarded.
  find "$DATA_DIR" -maxdepth 1 -name 'brew.lock.stale.*' \
    -exec rm -rf {} + 2>/dev/null || true
  [ -d "$BREW_LOCK" ] || return 0
  lock_mtime="$(brew_lock_mtime 2>/dev/null)" || return 0
  lock_now="$(date +%s)"
  [ "$((lock_now - lock_mtime))" -gt "$BREW_LOCK_MAX_AGE" ] || return 0
  # mv-aside: a lost race is ENOENT + re-mkdir; exclusivity is best-effort (above).
  mv "$BREW_LOCK" "$BREW_LOCK.stale.$$" 2>/dev/null || return 0
  rm -rf "$BREW_LOCK.stale.$$" 2>/dev/null || true
}

# probe: 2 stale arm-3 runs, brew asleep -> one upgrade, both exit 0.
# probe: lock backdated >600s -> mv'd aside; EXIT clears the new one.
# probe: foreign owner token -> release leaves the lock.
acquire_brew_lock() {
  mkdir -p "$DATA_DIR" || return 1
  break_stale_brew_lock
  mkdir "$BREW_LOCK" 2>/dev/null || return 1
  printf '%s\n' "$BREW_LOCK_TOKEN" >"$BREW_LOCK/owner" 2>/dev/null || {
    rm -rf "$BREW_LOCK" 2>/dev/null || true
    return 1
  }
  BREW_LOCK_HELD=1
}

# Pinned mode: the target release is the plugin.json version (single source of truth).
# head -n 1: a dependencies block carries its own "version" keys; only the first match
# is the plugin's own version.
TAG="v$(sed -n 's/.*"version": *"\([^"]*\)".*/\1/p' "$ROOT/.claude-plugin/plugin.json" | head -n 1)"

# Version output is compared v-stripped: goreleaser release binaries print the
# bare tag (v0.5.0) while brew formula builds stamp their own ldflags (0.5.0).
BARE="${TAG#v}"

extras_on_exit() { :; }
if [ -f "$ROOT/scripts/install-binary.extras.sh" ]; then
  . "$ROOT/scripts/install-binary.extras.sh"
fi
trap 'release_brew_lock; extras_on_exit' EXIT

# Arms 1+2: exact target exits, a dev build (describe/pseudo-version suffix, or
# the bare "dev" of an unstamped build) is never clobbered, a stale release or
# no version output falls through.
stale=""
if [ -x "$LINK" ]; then
  case "$("$LINK" --version 2>/dev/null | head -n 1)" in
    "$TAG" | "$BARE") exit 0 ;;
    dev | v[0-9]*[!0-9.]* | [0-9]*[!0-9.]*) exit 0 ;;
    v[0-9]* | [0-9]*) stale=1 ;;
    *) ;;
  esac
fi

# A stale-but-working binary never blocks its caller: hooks and MCP entrypoints
# run this script on their critical path, where a slow brew or GitHub
# round-trip in arms 3-6 kills MCP registration outright (the client's 30s
# connect timeout, never retried). Detach the refresh with all three stdio fds
# off the caller's pipes, keep serving the installed binary, and let the relink
# land for a later launch. A broken binary (no version output) still refreshes
# foreground; --sync (the detached child itself, or a caller that must block)
# forces the foreground path.
if [ -n "$stale" ] && [ "${1:-}" != "--sync" ]; then
  sh "$0" --sync </dev/null >/dev/null 2>&1 &
  exit 0
fi

mkdir -p "$ROOT/bin"

# Arm 3: a binary already on PATH wins (brew is authoritative even when it
# trails the pin). Exclude bin/ or the probe finds the managed symlink itself;
# entries are compared by inode (-ef), or a non-canonical spelling like
# "$ROOT/bin/", "$ROOT/bin/." or "$ROOT/bin//" evades the exclusion and $LINK
# becomes a self-loop.
# probe: PATH="$ROOT/bin/.:$PATH" (or bin/ or bin//) with a stale executable at
# bin/$NAME -> must never symlink bin/$NAME to itself; resolve elsewhere or
# fall through.
probe_path=
IFS_SAVE="$IFS"
IFS=:
for dir in $PATH; do
  if [ -n "$dir" ] && ! [ "$dir" -ef "$ROOT/bin" ]; then
    probe_path="$probe_path$dir:"
  fi
done
IFS="$IFS_SAVE"
probe() {
  (
    PATH="${probe_path%:}"
    command -v "$NAME" 2>/dev/null
  ) || true
}

sync_brew() {
  found="$(probe)"
  if [ -n "$found" ]; then
    case "$("$found" --version 2>/dev/null | head -n 1)" in
      "$TAG" | "$BARE" | v[0-9]*[!0-9.]* | [0-9]*[!0-9.]*) ;;
      *) brew upgrade "$BREW_PKG" >/dev/null 2>&1 || true ;;
    esac
    found="$(probe)"
    return 0
  fi
  brew install "$BREW_PKG" >/dev/null 2>&1 || true
  found="$(probe)"
}

found="$(probe)"
# Belt for the exclusion above: a probe result that is bin/$NAME's own
# directory entry under any path spelling must never be self-symlinked. The
# compare is on the parent directory's inode, not the resolved file — $LINK
# legitimately points at a stale brew binary the upgrade path must still see.
if [ -n "$found" ] && [ "$(dirname "$found")" -ef "$ROOT/bin" ]; then
  found=""
fi
if [ -n "$found" ]; then
  case "$("$found" --version 2>/dev/null | head -n 1)" in
    "$TAG" | "$BARE" | v[0-9]*[!0-9.]* | [0-9]*[!0-9.]*) ;;
    *)
      if acquire_brew_lock; then
        sync_brew
        release_brew_lock
      fi
      ;;
  esac
  if [ -n "$found" ]; then
    relink "$found"
    exit 0
  fi
fi

# Arm 4: brew present, binary absent. Best-effort — any failure (Homebrew
# tap-trust sandbox bug #22603, network) falls through to the direct download.
if command -v brew >/dev/null 2>&1; then
  # Lock wait: 6 acquire attempts, 5 sleeps of 2s between them (~10s nominal).
  brew_lock_acquired=0
  brew_lock_attempt=0
  while [ "$brew_lock_attempt" -lt 6 ]; do
    if acquire_brew_lock; then
      brew_lock_acquired=1
      break
    fi
    brew_lock_attempt=$((brew_lock_attempt + 1))
    [ "$brew_lock_attempt" -lt 6 ] || break
    sleep 2
  done
  if [ "$brew_lock_acquired" -eq 1 ]; then
    sync_brew
    release_brew_lock
  else
    # Lock wait lost: fall through — contended fresh installs may race the
    # download arms, which are concurrent-but-atomic (mktemp + mv).
    found="$(probe)"
  fi
  if [ -n "$found" ]; then
    relink "$found"
    exit 0
  fi
  echo "$NAME: Homebrew unavailable or failed (e.g. tap-trust #22603); using direct download" >&2
fi

# Arms 5+6: the durable data dir — reuse a payload already at the target
# release, else download the bare per-platform release binary, verified
# against goreleaser's checksums.txt.
os="$(uname -s | tr '[:upper:]' '[:lower:]')"
case "$os" in
  darwin | linux) ;;
  *)
    echo "$NAME: unsupported OS '$os'" >&2
    exit 1
    ;;
esac
arch="$(uname -m)"
case "$arch" in
  x86_64 | amd64) arch=amd64 ;;
  arm64 | aarch64) arch=arm64 ;;
  *)
    echo "$NAME: unsupported architecture '$arch'" >&2
    exit 1
    ;;
esac

sha256_of() {
  if command -v sha256sum >/dev/null 2>&1; then
    sha256sum "$1" | awk '{print $1}'
  else
    shasum -a 256 "$1" | awk '{print $1}'
  fi
}

asset="${NAME}_${os}_${arch}"
url="https://github.com/$REPO/releases/download/$TAG/$asset"
dest="$DATA_DIR/bin/$NAME"

# A durable payload already at the target release is reused: post-update
# reprovisioning (the plugin root swaps, the gitignored symlink is gone) is a
# symlink repair, not a re-download. A stale payload falls through and is
# overwritten by the download below.
# probe: seed $dest with a stub printing "$TAG", rm bin/$NAME, run with a
# brew-less curl-less PATH -> must symlink $dest and exit 0 without a fetch.
if [ -x "$dest" ]; then
  case "$("$dest" --version 2>/dev/null | head -n 1)" in
    "$TAG" | "$BARE")
      relink "$dest"
      exit 0
      ;;
  esac
fi

echo "$NAME: downloading $url" >&2
mkdir -p "$DATA_DIR/bin"
# Stage on the destination filesystem and rename into place: writing onto a
# running executable fails with ETXTBSY on Linux, and the rename keeps any
# still-executing inode alive.
tmp="$(mktemp "$DATA_DIR/bin/.$NAME.XXXXXX")"
trap 'rm -f "$tmp"; release_brew_lock; extras_on_exit' EXIT
curl -fsSL --retry 2 --connect-timeout 10 --max-time 300 -o "$tmp" "$url"

if ! sums="$(curl -fsSL --retry 2 --connect-timeout 10 --max-time 60 "https://github.com/$REPO/releases/download/$TAG/checksums.txt")"; then
  echo "$NAME: could not fetch checksums.txt for $TAG" >&2
  exit 1
fi
expected="$(printf '%s\n' "$sums" | awk -v a="$asset" '$2 == a {print $1}')"
if [ -z "$expected" ]; then
  echo "$NAME: no checksum for $asset in checksums.txt" >&2
  exit 1
fi
actual="$(sha256_of "$tmp")"
if [ "$actual" != "$expected" ]; then
  echo "$NAME: checksum mismatch for $asset (expected $expected, got $actual)" >&2
  exit 1
fi

chmod +x "$tmp"
mv -f "$tmp" "$dest"
relink "$dest"
echo "$NAME: installed $dest ($("$dest" --version))" >&2
